{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOzucgGAUtOGY+zmyfhRzG/"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","source":["import streamlit as st\n","import pandas as pd\n","\n","# Configuration de la page\n","st.set_page_config(\n","    page_title=\"Recommandations\",\n","    page_icon=\"🎥\",\n","    layout=\"wide\"\n",")\n","\n","# Charger les données des films\n","@st.cache_data\n","def load_data():\n","    return pd.read_csv(\"cinevasion/csv/films_acteurs.csv\")\n","\n","films = load_data()\n","\n","# Titre de la page\n","st.title(\"Recommandations de Films 🎬\")\n","\n","# Critères de recommandation (par exemple, les mieux notés)\n","top_rated = films.sort_values(by=\"averageRating\", ascending=False).head(10)\n","\n","# Afficher les recommandations\n","st.subheader(\"Films les mieux notés\")\n","cols = st.columns(5)  # Afficher 5 films par ligne\n","\n","for i, (_, film) in enumerate(top_rated.iterrows()):\n","    with cols[i % 5]:\n","        st.image(film[\"poster_path\"], use_column_width=True)\n","        st.write(f\"**{film['title']}**\")\n","        st.caption(f\"Note : {film['averageRating']} ({film['numVotes']} votes)\")\n","        if st.button(f\"Détails {i}\", key=f\"btn_details_{i}\"):\n","            st.session_state[\"selected_film_tconst\"] = film[\"tconst\"]\n","            st.experimental_set_query_params(page=\"details_page\")\n","\n","# Navigation entre les pages\n","st.sidebar.title(\"Navigation\")\n","page = st.sidebar.radio(\"Pages\", [\"Home\", \"Recommandations\", \"Similarity Page\"])\n","\n","if page == \"Home\":\n","    st.experimental_set_query_params(page=\"home_page\")\n","elif page == \"Recommendations\":\n","    st.experimental_set_query_params(page=\"recommendations_page\")\n","elif page == \"Similarity Page\":\n","    st.experimental_set_query_params(page=\"similarity_page\")"],"metadata":{"id":"v0yO_vLSZRAi"},"execution_count":null,"outputs":[]}]}